.pw-eye:hover{color:var(--gold)}
.pw-match{font-size:.72rem;margin-top:.28rem;font-weight:500}
.pw-match.ok{color:var(--gn)}
.pw-match.no{color:#E87070}
.btn-sub{width:100%;padding:.9rem;background:var(--gold);color:var(--dk);
