.btn-sub:hover{background:var(--gold-l);transform:translateY(-1px)}
.btn-sub:disabled{opacity:.52;cursor:not-allowed;transform:none}
.err-msg{background:var(--rd-dim);border:1px solid rgba(192,57,43,.3);
